import { AppSidebar } from "./components/app-sidebar"
import {
    SidebarInset,
    SidebarProvider,
} from "@/components/ui/sidebar"


export const DashboardLayout = ({ children, onNavigate, currentView }: { children: React.ReactNode; onNavigate?: (view: string) => void; currentView?: string }) => {
    return (
        <SidebarProvider className="h-svh overflow-hidden">
            <AppSidebar onNavigate={onNavigate} currentView={currentView} />
            <SidebarInset className="overflow-hidden min-h-0">
                {children}
            </SidebarInset>
        </SidebarProvider>
    )
}

import { useState } from 'react'
import { DashboardLayout } from './dashboardLayout'
import { ActiveStreamViews } from './activeStreamViews'

export default function IncidentManagementDashboardDemo() {
    const [currentView, setCurrentView] = useState("Activity Stream");

    const renderContent = () => {
        switch (currentView) {
            case "Activity Stream":
                return <ActiveStreamViews />;
            default:
                return <ActiveStreamViews />;
        }
    };

    return (
        <DashboardLayout onNavigate={setCurrentView} currentView={currentView}>
            {renderContent()}
        </DashboardLayout>
    )
}
